mapper.select:
SELECT se.evaluation_id, se.order_id, se.staff_id, s.staff_name, se.provider_id, p.provider_name, se.elder_id, e.elder_name AS elder_name, o.service_type_code, o.service_type_name, se.attitude_score, se.quality_score, se.efficiency_score, se.overall_score, se.average_score, se.evaluation_content, se.evaluation_tags, se.is_anonymous, se.evaluation_time, se.create_time FROM t_service_evaluation se LEFT JOIN t_staff s ON se.staff_id = s.staff_id LEFT JOIN t_provider p ON se.provider_id = p.provider_id LEFT JOIN t_elder e ON se.elder_id = e.elder_id LEFT JOIN t_order o ON se.order_id = o.order_id WHERE se.deleted = 0
AND se.provider_id = #{query.providerId}
AND se.staff_id = #{query.staffId}
AND se.order_id = #{query.orderId}
AND se.elder_id = #{query.elderId}
AND o.order_no LIKE CONCAT('%', #{query.orderNo}, '%')
AND e.elder_name LIKE CONCAT('%', #{query.elderName}, '%')
AND p.provider_name LIKE CONCAT('%', #{query.providerName}, '%')
AND o.service_type_code = #{query.serviceTypeCode}
AND se.average_score >= #{query.minRating}
AND se.average_score <= #{query.maxRating}
AND DATE(se.create_time) >= #{query.startDate}
AND DATE(se.create_time) <= #{query.endDate}
ORDER BY se.create_time DESC
